<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin-install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/usb</span></span>
